#include<bits/stdc++.h>
using namespace std;

int n;
string x;
bool pan(string x){
    int ans1=0,ans2=0;
    for(int i=x.size()-1;i>=0;i--){
        if(i%2==0) ans2+=(x[i]-'0');
        else ans1+=(x[i]-'0');
    }
    if(abs(ans1-ans2)%11==0) return 1;
    return 0;
}
int main(){
    cin>>n;
    while(n--){
        cin>>x;
        if(pan(x)) cout<<"Yes\n";
        else cout<<"No\n";
    }
}
